// Utility: shuffle an array (Fisher-Yates)
export function shuffleQuestions(arr: TriviaQuestion[]): TriviaQuestion[] {
  const a = [...arr]
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[a[i], a[j]] = [a[j], a[i]]
  }
  return a
}

function shuffleOptions(q: TriviaQuestion): TriviaQuestion {
  const correctAnswer = q.options[q.answer]
  const shuffled = [...q.options]
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]]
  }
  return { ...q, options: shuffled, answer: shuffled.indexOf(correctAnswer) }
}

// Pick N random question indices
export function pickQuestionIndices(n: number): number[] {
  const indices = Array.from({ length: TRIVIA_QUESTIONS.length }, (_, i) => i)
  for (let i = indices.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[indices[i], indices[j]] = [indices[j], indices[i]]
  }
  return indices.slice(0, n)
}

import AsyncStorage from '@react-native-async-storage/async-storage'

// Get questions by indices
export function getQuestionsByIndices(indices: number[]): TriviaQuestion[] {
  return indices.map(idx => {
    const q = TRIVIA_QUESTIONS[idx]
    if (!q) return TRIVIA_QUESTIONS[0] // Fallback
    return shuffleOptions(q)
  })
}

// Pick N unique question indices to prevent repeating
export async function pickUniqueQuestionIndices(n: number): Promise<number[]> {
  try {
    const SEEN_KEY = '@trivia_seen_indices'
    const stored = await AsyncStorage.getItem(SEEN_KEY)
    let seen: number[] = stored ? JSON.parse(stored) : []

    // If we've seen too many, reset the seen list to avoid running out
    if (seen.length > TRIVIA_QUESTIONS.length - n * 2) {
      seen = []
    }

    const available = Array.from({ length: TRIVIA_QUESTIONS.length }, (_, i) => i)
      .filter(i => !seen.includes(i))

    // Shuffle available pool
    for (let i = available.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1))
      ;[available[i], available[j]] = [available[j], available[i]]
    }

    const picked = available.slice(0, n)
    
    // Save new seen list
    await AsyncStorage.setItem(SEEN_KEY, JSON.stringify([...seen, ...picked]))
    
    return picked
  } catch (err) {
    // Fallback to purely random if storage fails
    return pickQuestionIndices(n)
  }
}

// Pick N random questions, optionally from specific subjects
export function pickQuestions(n: number, subjects?: string[]): TriviaQuestion[] {
  const pool = subjects
    ? TRIVIA_QUESTIONS.filter(q => subjects.includes(q.subject))
    : TRIVIA_QUESTIONS
  return shuffleQuestions(pool).slice(0, n).map(shuffleOptions)
}
